describe("X.509 verifier", () => {
  it("accepts a valid x5c chain anchored by configured root PEM", () => {
    const x5c = pemCertificatesToX5c(`${LEAF_CERT}\n${ROOT_CERT}`);
    const result = verifyX509ChainFromHeader(
      { x5c },
      { trustAnchorsPem: ROOT_CERT, now: new Date("2026-06-10T00:00:00Z") }
    );

    assert.equal(result.pass, true);
    assert.equal(result.chain.length, 2);
  });

  it("fails closed when the chain does not match a configured trust anchor", () => {
    const x5c = pemCertificatesToX5c(`${LEAF_CERT}\n${ROOT_CERT}`);
    const result = verifyX509ChainFromHeader(
      { x5c },
      { trustAnchorSha256: "00", now: new Date("2026-06-10T00:00:00Z") }
    );

    assert.equal(result.pass, false);
    assert.equal(result.errorCode, "x509_chain_untrusted");
  });

  it("requires configured issuer identity to be bound in the certificate SAN", () => {
    const [leaf] = parseX5cChain(pemCertificatesToX5c(`${LEAF_CERT}\n${ROOT_CERT}`));

    const pass = validateCertificateIdentity(leaf, "https://tier2.example.test", {
      x509_san_uri: "https://tier2.example.test",
    });
    assert.equal(pass.pass, true);

    const fail = validateCertificateIdentity(leaf, "https://other.example.test", {
      x509_san_uri: "https://other.example.test",
    });
    assert.equal(fail.pass, false);
    assert.equal(fail.errorCode, "x509_subject_mismatch");
  });
});
